// 1. Get existing leads from your Google Sheet (from the 'Get row(s)' node)
// Note: Ensure the column name matches exactly what is in your sheet
const existingLeads = $("Get row(s) in sheet").all().map(item => item.json["Channel URLs"] || "");

// 2. Get the new search results from YouTube
const youtubeItems = $input.first().json.items || [];

// 3. Process and Filter
const results = youtubeItems
  .map(item => {
    const channelId = item.snippet.channelId;
    const channelUrl = `https://www.youtube.com/channel/${channelId}`;
    return { channelId, channelUrl };
  })
  // Deduplicate within the current search batch
  .filter((v, i, a) => a.findIndex(t => t.channelId === v.channelId) === i)
  // Deduplicate against the Google Sheet (Master List)
  .filter(item => !existingLeads.includes(item.channelUrl));

// 4. Handle Empty Data (Prevents the workflow from breaking)
if (results.length === 0) {
  return []; // n8n will stop execution here gracefully
}

return results.map(res => ({
  json: {
    channelId: res.channelId,
    channelUrl: res.channelUrl
  }
}));

