const items = $input.all();
const uniqueUrls = new Set();

items.forEach(item => {
  // Check for the specific key "Channel URLs" that your data currently has
  // Also checking "YouTube Channel URL" just in case your sheet headers vary
  const channelUrl = item.json["Channel URLs"] || item.json["YouTube Channel URL"];

  if (channelUrl && channelUrl.trim() !== "") {
    uniqueUrls.add(channelUrl.trim());
  }
});

const channelsArray = Array.from(uniqueUrls);

// Handle the "Empty Data" scenario you were worried about
if (channelsArray.length === 0) {
    return [{
        json: {
            channels: [],
            message: "No valid channel URLs found in the input data."
        }
    }];
}

return [{
  json: {
    channels: channelsArray
  }
}];

// 1. Get items from the two sheets
const whaleData = $('Whale Channel Reply System Data').all();
const messagedData = $input.all(); // This is the input from 'Messaged Leads Data'

// 2. Identify the correct key (Column Name)
// Using your shared data, the column is "Channel URLs"
const whaleKey = "Channel URLs";
const messagedKey = "YouTube Channel URL"; // Ensure this matches your 'Messaged' sheet header

// 3. Create a Set of URLs we have ALREADY messaged (for O(1) lookup speed)
const messagedSet = new Set(
  messagedData
    .map(item => item.json[messagedKey] ? item.json[messagedKey].trim() : null)
    .filter(url => url)
);

// 4. Filter out the whales we've already contacted
const newChannels = whaleData
  .map(item => item.json[whaleKey] ? item.json[whaleKey].trim() : null)
  .filter(url => url && !messagedSet.has(url));

// 5. Deduplicate the new list (just in case the search ran twice)
const uniqueNewChannels = [...new Set(newChannels)];

// 6. Extract the ID safely (Handles trailing slashes or @handles)
const channelsWithIds = uniqueNewChannels.map(url => {
  // Removes trailing slash if it exists, then grabs the last segment
  const cleanUrl = url.replace(/\/$/, ""); 
  const channelId = cleanUrl.split('/').pop(); 

  return {
    channelUrl: url,
    channelId: channelId
  };
});

// 7. Return the structured data for the "Split Out" node
return [{
  json: {
    channels: channelsWithIds,
    totalWhalesFound: whaleData.length,
    alreadyMessaged: messagedSet.size,
    newLeadsToContact: channelsWithIds.length
  }
}];

