const prompt = `You are writing cold outreach emails on behalf of AlgoNova Labs.

We offer a YouTube Revenue Recovery System. Our core service is an automated Link Audit that identifies dead affiliate links and out-of-stock products in a creator's library, then auto-updates them to recover lost commissions.

TARGET: YouTubers with 10k–500k subscribers who made product review, comparison, or "best of" videos in 2023-2024.

THE CORE INSIGHT:
Creators with "evergreen" affiliate content from 2023-2024 are losing 15-20% of their passive income because their links have "decayed" (broken URLs, changed affiliate programs, or discontinued products). Their old videos still get views, but the money leaks out through dead links.

FOR EACH CHANNEL BELOW, write ONE outreach message.

CRITICAL RULES:
1. Reference their LATEST video specifically in the hook (not their old 2023-2024 content)
2. Connect the latest video to the link decay problem (e.g., "still making product content means your 2023 links are bleeding money")
3. DO NOT mention "comment management" or "engagement" — this is about REVENUE RECOVERY from dead affiliate links

OUTPUT: Valid JSON array only.

JSON Structure:
[
  {
    "YouTube Channel URL": "https://www.youtube.com/channel/CHANNEL_ID",
    "Channel ID": "CHANNEL_ID",
    "Niche": "identified_niche",
    "Generated Message": "exactly 3 sentences",
    "Subject": "6-10 words"
  }
]

CHANNELS TO PROCESS:
${formattedData}`;

return [{
  json: {
    chatInput: prompt
  }
}];

let aiResponse;
try {
  const inputData = $input.first().json;
  if (inputData.output && Array.isArray(inputData.output)) {
    const firstOutput = inputData.output[0];
    if (firstOutput && firstOutput.content && firstOutput.content[0] && firstOutput.content[0].text) {
      aiResponse = firstOutput.content[0].text;
    } else {
      throw new Error('output array exists but missing content[0].text');
    }
  } else if (inputData.content && inputData.content.parts && inputData.content.parts[0]) {
    aiResponse = inputData.content.parts[0].text;
  } else if (inputData.message && inputData.message.content && inputData.message.content[0]) {
    aiResponse = inputData.message.content[0].text;
  } else if (inputData.text) {
    aiResponse = inputData.text;
  } else if (typeof inputData === 'string') {
    aiResponse = inputData;
  } else {
    return [{
      json: {
        error: true,
        message: 'Unknown AI response structure',
        rawResponse: JSON.stringify(inputData, null, 2)
      }
    }];
  }
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Error accessing AI response: ${error.message}`,
      rawInput: JSON.stringify($input.first().json, null, 2)
    }
  }];
}

let parsedData;
try {
  let cleanedResponse = aiResponse.trim();
  if (cleanedResponse.startsWith('```json')) {
    cleanedResponse = cleanedResponse.replace(/^```json\n?/, '').replace(/\n?```$/, '');
  } else if (cleanedResponse.startsWith('```')) {
    cleanedResponse = cleanedResponse.replace(/^```\n?/, '').replace(/\n?```$/, '');
  }
  parsedData = JSON.parse(cleanedResponse);
} catch (error) {
  return [{
    json: {
      error: true,
      message: `Failed to parse JSON: ${error.message}`,
      rawResponse: aiResponse
    }
  }];
}

if (!Array.isArray(parsedData)) {
  return [{
    json: {
      error: true,
      message: 'AI response is not an array',
      parsedData: parsedData
    }
  }];
}

const results = parsedData.map((item, index) => {
  const channelId = item['Channel ID'] || 'ERROR: Missing Channel ID';
  return {
    json: {
      "YouTube Channel URL": `https://www.youtube.com/channel/${channelId}`,
      "Channel ID": channelId,
      "Niche": item['Niche'] || 'ERROR: Missing Niche',
      "Generated Message": item['Generated Message'] || 'ERROR: Missing Message',
      "Subject": item['Subject'] || 'ERROR: Missing Subject'
    },
    // Store the data in pairedItem so it flows through the Apify actor
    pairedItem: {
      item: index
    }
  };
});

return results;

// Node name: "Merge Channel & Video Data"
const channelItems = $('Upload Playlists').all();
const videoItems = $input.all();

const results = channelItems.map((channelItem, index) => {
  const channelData = channelItem.json;
  const videoData = videoItems[index]?.json;

  const latestVideoTitle = videoData?.items && videoData.items.length > 0 
    ? videoData.items[0].snippet.title 
    : 'N/A';

  return {
    json: {
      channelId: channelData.channelId,
      channelTitle: channelData.channelTitle,
      channelDescription: channelData.channelDescription,
      latestVideoTitle: latestVideoTitle
    }
  };
});

return results;

const messageItems = $('Code in JavaScript3').all();
const emailItems = $input.all();

const results = emailItems.map((emailItem) => {
  const emailData = emailItem.json;

  // Find the matching message by Channel ID
  const matchingMessage = messageItems.find(
    msg => msg.json["Channel ID"] === emailData.ChannelId
  );

  if (!matchingMessage) {
    return {
      json: {
        error: true,
        message: "Could not find matching message data",
        emailData: emailData
      }
    };
  }

  return {
    json: {
      "Email": emailData.Email || "no-email@found.com",
      "YouTube Channel URL": matchingMessage.json["YouTube Channel URL"],
      "Channel ID": matchingMessage.json["Channel ID"],
      "Niche": matchingMessage.json.Niche,
      "Message ": matchingMessage.json["Generated Message"],
      "Subject": matchingMessage.json.Subject,
      "ChannelName": emailData.ChannelName,
      "SubscriberCount": emailData.SubscriberCount
    }
  };
});

return results;
